import { executeRequest } from "../../src/lib/http";
import { getJwt } from "../../src/lib/authentication";

jest.mock("../../src/lib/authentication");

describe("Http", () => {
  const url = "http://test.test/test?test=test";
  const defaultContentType = "application/json";
  const responsePayloadJSON = {
    test: "test"
  };
  const headers = new Headers();
  headers.set("Content-Type", defaultContentType);
  const responsePayloadString = "test_test";
  const consumerKey = "test_consumer_key";
  const authorizationHeader = "authorizationHeader_123";
  const customHeaderAccept = "application/json+stream";
  const customHeaderContentType = "application/xml";
  const customHeaderAuthorization = "test_123";

  getJwt.mockReturnValue(authorizationHeader);

  describe("executeRequest", () => {
    it("should set default 'Accept' header if not passed", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(responsePayloadJSON);
    });

    it("should use provided 'Accept' header value and not the default one", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url, headers: new Headers({ Accept: customHeaderAccept }) });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: customHeaderAccept,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(responsePayloadJSON);
    });

    it("should set default 'Content-Type' header if not passed and the method supports payload", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url, method: "POST", body: responsePayloadJSON });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: JSON.stringify(responsePayloadJSON),
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`,
          "Content-Type": defaultContentType
        }),
        method: "POST"
      });
      expect(result).toBe(responsePayloadJSON);
    });

    it("should set multipart 'Content-Type' header if payload is instance of formData and the method supports payload", async () => {
      const formData = new FormData();
      formData.append(
        "test123",
        new Blob([JSON.stringify(responsePayloadJSON)], {
          type: "application/json"
        })
      );

      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url, method: "POST", body: formData });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(
        url,
        expect.objectContaining({
          method: "POST",
          body: formData,
          credentials: "same-origin",
          headers: new Headers({
            Accept: defaultContentType,
            Authorization: `Bearer ${authorizationHeader}`,
            "Content-Type": "multipart/formdata"
          })
        })
      );

      expect(result).toBe(responsePayloadJSON);
    });

    it("should use provided 'Content-Type' header value and not the default one", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({
        url,
        method: "PUT",
        body: responsePayloadJSON,
        headers: new Headers({
          "Content-Type": customHeaderContentType
        })
      });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        // NOTE: the payload is not stringified
        // since the call contains explicit value
        // for the content type, so the payload
        // is left intact
        body: responsePayloadJSON,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`,
          "Content-Type": customHeaderContentType
        }),
        method: "PUT"
      });
      expect(result).toBe(responsePayloadJSON);
    });

    it("should set default 'Authorization' header if not passed", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(responsePayloadJSON);
    });

    it("should use provided 'Authorization' header value and not the default one", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url, headers: new Headers({ Authorization: customHeaderAuthorization }) });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `${customHeaderAuthorization}`
        }),
        method: "GET"
      });
      expect(result).toBe(responsePayloadJSON);
    });

    it("should set 'Consumer-Key' header if consumer key is passed", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url, consumerKey });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`,
          "Consumer-Key": consumerKey
        }),
        method: "GET"
      });
      expect(result).toBe(responsePayloadJSON);
    });

    it("should throw an error if response is not 'OK'", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: false,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      await expect(async () => {
        await executeRequest({ url });
      }).rejects.toBeTruthy();

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
    });

    it("should return no data if response status is 204", async () => {
      global.fetch = jest.fn().mockImplementationOnce(() =>
        Promise.resolve({
          ok: true,
          status: 204,
          json: () => Promise.resolve(responsePayloadJSON),
          headers
        })
      );

      const result = await executeRequest({ url });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(undefined);
    });

    it("should return raw response if 'rawResponse' is set to true", async () => {
      const response = {
        ok: true,
        json: () => Promise.resolve(responsePayloadString),
        headers
      };
      global.fetch = jest.fn().mockImplementationOnce(() => Promise.resolve(response));

      const result = await executeRequest({ url, rawResponse: true });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(response);
    });

    it("should return raw response if 'rawResponse' is set to true, status is 204", async () => {
      const response = {
        ok: true,
        status: 204,
        json: () => Promise.resolve(responsePayloadString),
        headers
      };
      global.fetch = jest.fn().mockImplementationOnce(() => Promise.resolve(response));

      const result = await executeRequest({ url, rawResponse: true });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(response);
    });

    it("should return raw response if 'Content-Type' from response is not the default content type", async () => {
      const headersLocal = new Headers();
      headersLocal.set("Content-Type", "application/text");

      const testBody = "test_body";
      const response = {
        ok: true,
        json: () => Promise.resolve(responsePayloadString),
        headers: headersLocal,
        text: () => Promise.resolve(testBody)
      };
      global.fetch = jest.fn().mockImplementationOnce(() => Promise.resolve(response));

      const result = await executeRequest({ url });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(testBody);
    });

    it("should throw an error if rawResponse is not set and response.json() fails", async () => {
      const response = {
        ok: true
      };
      global.fetch = jest.fn().mockImplementationOnce(() => Promise.resolve(response));

      const result = await executeRequest({ url });

      expect(global.fetch).toBeCalledTimes(1);
      expect(global.fetch).toBeCalledWith(url, {
        body: null,
        credentials: "same-origin",
        headers: new Headers({
          Accept: defaultContentType,
          Authorization: `Bearer ${authorizationHeader}`
        }),
        method: "GET"
      });
      expect(result).toBe(response);
    });

    it("should abort the fetch request when controller.abort() is called", async () => {
      const abortController = new AbortController();
      const signal = abortController.signal;

      global.fetch = jest.fn(
        () =>
          new Promise((resolve, reject) => {
            signal.addEventListener("abort", () => {
              reject(new DOMException("The user aborted a request.", "AbortError"));
            });
          })
      );

      const fetchPromise = executeRequest({ url, signal });

      abortController.abort();

      await expect(fetchPromise).rejects.toThrow("The user aborted a request.");
    });
  });
});
